INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-01899', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於常用的角膜地形圖各項參數，下列敘述何者錯誤？', '["角膜表面非對稱指數（surface asymmetry index, SAI），是指同一經線上之對等位置（相距180度）， 角膜弧度的差值", "表面規則指數（surface regularity index, SRI），可用來評估瞳孔範圍角膜表面的平滑度，SRI值愈 趨近於1，角膜表面愈規則平滑", "潛視力（potential visual acuity, PVA），是指根據角膜地形圖結果的預測視力", "偏心率（eccentricity value, e值），正常角膜依扁橢圓形成非球面，愈往周邊弧度愈平坦，這差異 值，即為偏心率，正常值約在0.40-0.57之間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01900', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關細隙燈用於前眼部的檢查，下列敘述何者錯誤？', '["細隙燈可用於配戴隱形眼鏡前後的健康評估", "可觀察鏡片滑動與角膜弧度是否貼合", "淚液試紙試驗需要用到細隙燈", "角膜面紗狀淺凹（dimple veiling），用間接照射法來觀察最好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01901', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜弧度測量，下列敘述何者錯誤？', '["角膜中心的弧度較陡，周邊弧度較平", "角膜弧度測量儀（keratometry）只能測得角膜頂點（apex）的弧度，無法測量周邊角膜的弧度", "測量值為45.00D@180, 47.00D@090，表示有-2.00 D的角膜順散光", "角膜頂點若偏移，測量值會不準"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01902', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關角膜的生理特性，下列敘述何者錯誤？', '["具有豐富的血管提供其需要代謝的養分", "角膜上皮細胞為透明，正常細胞不含色素", "當角膜含水量上升，角膜厚度會變厚", "圓錐角膜之角膜厚度會變薄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01903', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者是因配戴隱形眼鏡可能見到的併發症？', '["青光眼", "點狀角膜炎或角膜上皮缺損", "白內障", "圓錐角膜"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01904', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於造成眼睛紅的症狀原因，下列敘述何者正確？', '["隱形眼鏡相關的眼角膜病變常呈現眼角膜周邊輪狀充血", "急性傳染性結膜炎常呈現眼角膜周邊輪狀充血", "眼結膜下鮮紅色片狀出血常造成眼內玻璃體出血", "急性傳染性結膜炎常造成眼睛紅，但不會合併結膜乳突或濾泡現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01905', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關減輕或改善角膜缺氧的方式，下列何者錯誤？', '["配戴軟式的鏡片應選擇矽水膠材質鏡片", "儘量不要在夜間睡眠時間配戴鏡片", "降低任何一種鏡片配戴的時間", "配戴硬式的鏡片選擇滑動越少的鏡片越好"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01906', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡相關的細菌性角膜感染，下列敘述何者正確？', '["最常見的病原菌為念珠菌", "通常伴隨著疼痛、流淚、怕光等症狀", "常見於角膜輪部區及周邊區域", "通常不需要治療就能夠自行痊癒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01907', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關矽氧烷丙烯酸酯（silicone/acrylate）材質製成的隱形眼鏡，當鏡片中矽含量越高時則材質特性的 變化，下列敘述何者正確？', '["越不易有沉積物附著", "鏡片透氧性越低", "鏡片濕潤性越好", "鏡片硬度越低"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01908', 'optician', 'optician-moex-108-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡引起的瞼結膜充血（palpebral hyperemia）之敘述，下列何者錯誤？', '["可能發展為巨大乳突結膜炎的前奏", "可先停止配戴隱形眼鏡，換成無防腐劑之隱形眼鏡的護理藥水", "使用裂隙燈檢查可發現充血而無細胞浸潤，表示可能為物理性刺激引起", "若有眼癢、燒灼感、異物感、輕度充血，分泌物少則為細菌性結膜炎（bacterial conjunctivitis）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:35+00:00", "source_pdf_sha1": "93c9062a697c", "answer_pdf_sha1": "3d13dcd1ce1a", "source_family": "moex-gov-tw", "moex": {"exam_code": "108110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "108", "exam_name": "108年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、108年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
